1	export type Cell = [number, number];
2	
3	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const livesNextGeneration = (isAlive: boolean, neighborCount: number): boolean =>
6	  neighborCount === 3 || (isAlive && neighborCount === 2);
7	
8	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
9	  [-1, -1], [-1, 0], [-1, 1],
10	  [0, -1],           [0, 1],
11	  [1, -1],  [1, 0],  [1, 1],
12	];
13	
14	export function nextGeneration(liveCells: Cell[]): Cell[] {
15	  const liveKeys = new Set(liveCells.map(keyOf));
16	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
17	  for (const [x, y] of liveCells) {
18	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
19	      const neighbor: Cell = [x + dx, y + dy];
20	      const k = keyOf(neighbor);
21	      const entry = neighborCounts.get(k);
22	      if (entry) entry.count++;
23	      else neighborCounts.set(k, { cell: neighbor, count: 1 });
24	    }
25	  }
26	  const result: Cell[] = [];
27	  for (const [k, { cell, count }] of neighborCounts) {
28	    if (livesNextGeneration(liveKeys.has(k), count)) result.push(cell);
29	  }
30	  return result;
31	}
