1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array when given empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells each with only 1 neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block (2x2) unchanged as a still life (survival)", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    expect(new Set(nextGeneration(block).map((c) => c.join(",")))).toEqual(
17	      new Set(block.map((c) => c.join(","))),
18	    );
19	  });
20	  it("should transform a vertical blinker into a horizontal blinker (oscillator)", () => {
21	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
22	    const horizontal: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
23	    expect(new Set(nextGeneration(vertical).map((c) => c.join(",")))).toEqual(
24	      new Set(horizontal.map((c) => c.join(","))),
25	    );
26	  });
27	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
28	    const input: [number, number][] = [
29	      [0, 0], [1, 0], [2, 0],
30	      [1, 1],
31	      [0, 2], [1, 2], [2, 2],
32	    ];
33	    const result = new Set(nextGeneration(input).map((c) => c.join(",")));
34	    expect(result.has("1,1")).toBe(false);
35	  });
36	  it("should bring a dead cell with exactly 3 neighbors to life (reproduction)", () => {
37	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1]];
38	    const result = new Set(nextGeneration(input).map((c) => c.join(",")));
39	    expect(result.has("1,1")).toBe(true);
40	  });
41	  it("should handle negative coordinates", () => {
42	    const verticalBlinker: [number, number][] = [[-5, -1], [-5, 0], [-5, 1]];
43	    const expectedHorizontal: [number, number][] = [[-6, 0], [-5, 0], [-4, 0]];
44	    expect(new Set(nextGeneration(verticalBlinker).map((c) => c.join(",")))).toEqual(
